export function uncapitalize(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/** Indents every line of `text` by `n` spaces. */
export function indent(text: string, n: number): string {
  const pad = ' '.repeat(n)
  return text
    .split('\n')
    .map((line) => (line.length > 0 ? pad + line : line))
    .join('\n')
}

/** Wraps a raw TypeScript type string with list/nullable modifiers. */
export function wrapType(baseType: string, isList: boolean, isRequired: boolean): string {
  let result = baseType
  if (isList) {
    result = `${result}[]`
  }
  if (!isRequired) {
    result = `${result} | null`
  }
  return result
}

