import type * as DMMF from '@prisma/dmmf'

import { indent, uncapitalize, wrapType } from './template'
import { prismaTypeToTypeScript } from './type-mapping'

export type GenerateClientOptions = {
  models: readonly DMMF.Model[]
  enums: readonly DMMF.DatamodelEnum[]
  baseUrl: string
}

type FieldInfo = {
  name: string
  tsType: string
  isRequired: boolean
  isList: boolean
  isId: boolean
  hasDefaultValue: boolean
  isReadOnly: boolean
  isUpdatedAt: boolean
}

type IdField = {
  name: string
  tsType: string
}

/**
 * Generates a complete typed REST API client as a TypeScript source string
 * from DMMF model and enum definitions.
 */
export function generateRestClient(options: GenerateClientOptions): string {
  const sections: string[] = []

  sections.push(HEADER)

  if (options.enums.length > 0) {
    for (const enumDef of options.enums) {
      sections.push(generateEnum(enumDef))
    }
    sections.push('')
  }

  for (const model of options.models) {
    const fields = getScalarFields(model)
    sections.push(generateModelInterface(model.name, fields))
    sections.push(generateCreateInput(model.name, fields))
    sections.push(generateUpdateInput(model.name, fields))
  }

  sections.push(generateClientClass(options.models, options.baseUrl))

  return sections.join('\n')
}

const HEADER = `// Generated by @prisma/generator-rest-client
// DO NOT EDIT MANUALLY
`

function getScalarFields(model: DMMF.Model): FieldInfo[] {
  const fields: FieldInfo[] = []
  for (const field of model.fields) {
    if (field.kind === 'object' || field.kind === 'unsupported') {
      continue
    }
    const tsType = field.kind === 'enum' ? field.type : prismaTypeToTypeScript(field.type)
    fields.push({
      name: field.name,
      tsType,
      isRequired: field.isRequired,
      isList: field.isList,
      isId: field.isId,
      hasDefaultValue: field.hasDefaultValue,
      isReadOnly: field.isReadOnly,
      isUpdatedAt: field.isUpdatedAt ?? false,
    })
  }
  return fields
}

function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}\n`
}

function generateModelInterface(modelName: string, fields: FieldInfo[]): string {
  const lines = fields.map((f) => {
    const type = wrapType(f.tsType, f.isList, f.isRequired)
    return `  ${f.name}: ${type}`
  })
  return `export interface ${modelName} {\n${lines.join('\n')}\n}\n`
}

function generateCreateInput(modelName: string, fields: FieldInfo[]): string {
  const lines: string[] = []
  for (const f of fields) {
    if (f.isReadOnly || f.isUpdatedAt) continue
    if (f.isId && f.hasDefaultValue) continue

    const optional = f.hasDefaultValue || !f.isRequired
    const type = wrapType(f.tsType, f.isList, f.isRequired)
    const marker = optional ? '?' : ''
    lines.push(`  ${f.name}${marker}: ${type}`)
  }
  return `export interface ${modelName}CreateInput {\n${lines.join('\n')}\n}\n`
}

function generateUpdateInput(modelName: string, fields: FieldInfo[]): string {
  const lines: string[] = []
  for (const f of fields) {
    if (f.isReadOnly || f.isUpdatedAt) continue
    if (f.isId && f.hasDefaultValue) continue

    const type = wrapType(f.tsType, f.isList, f.isRequired)
    lines.push(`  ${f.name}?: ${type}`)
  }
  return `export interface ${modelName}UpdateInput {\n${lines.join('\n')}\n}\n`
}

function findIdField(model: DMMF.Model, fields: FieldInfo[]): IdField | null {
  const idField = fields.find((f) => f.isId)
  if (idField) {
    return { name: idField.name, tsType: idField.tsType }
  }

  if (model.primaryKey && model.primaryKey.fields.length > 0) {
    const compoundFields = model.primaryKey.fields
      .map((name) => fields.find((f) => f.name === name))
      .filter((f): f is FieldInfo => f !== undefined)

    if (compoundFields.length === 1) {
      return { name: compoundFields[0].name, tsType: compoundFields[0].tsType }
    }

    if (compoundFields.length > 1) {
      const objType = compoundFields.map((f) => `${f.name}: ${f.tsType}`).join('; ')
      return { name: model.primaryKey.name ?? 'id', tsType: `{ ${objType} }` }
    }
  }

  const uniqueField = fields.find((f) => {
    const dmmfField = model.fields.find((df) => df.name === f.name)
    return dmmfField?.isUnique
  })
  if (uniqueField) {
    return { name: uniqueField.name, tsType: uniqueField.tsType }
  }

  return null
}

function generateClientClass(models: readonly DMMF.Model[], baseUrl: string): string {
  const lines: string[] = []
  lines.push(`export class RestClient {`)
  lines.push(`  #baseUrl: string`)
  lines.push(``)
  lines.push(`  constructor(baseUrl: string = '${baseUrl}') {`)
  lines.push(`    this.#baseUrl = baseUrl`)
  lines.push(`  }`)

  for (const model of models) {
    const fields = getScalarFields(model)
    const propName = uncapitalize(model.name)
    const path = model.name.toLowerCase()
    const idField = findIdField(model, fields)

    lines.push(``)
    lines.push(indent(generateModelAccessor(model.name, propName, path, idField), 2))
  }

  lines.push(`}`)
  lines.push(``)
  return lines.join('\n')
}

function generateModelAccessor(
  modelName: string,
  propName: string,
  path: string,
  idField: IdField | null,
): string {
  const lines: string[] = []
  lines.push(`readonly ${propName} = {`)

  // findMany
  lines.push(`  findMany: async (): Promise<${modelName}[]> => {`)
  lines.push(`    const res = await fetch(\`\${this.#baseUrl}/${path}\`)`)
  lines.push(`    if (!res.ok) throw new Error(\`GET /${path} failed: \${res.status}\`)`)
  lines.push(`    return res.json()`)
  lines.push(`  },`)

  if (idField) {
    const isCompound = idField.tsType.startsWith('{')
    const idParam = isCompound ? `id: ${idField.tsType}` : `${idField.name}: ${modelName}['${idField.name}']`
    const idPathSegment = isCompound
      ? `\${Object.values(id).join('/')}`
      : `\${${idField.name}}`

    // findUnique
    lines.push(`  findUnique: async (${idParam}): Promise<${modelName} | null> => {`)
    lines.push(`    const res = await fetch(\`\${this.#baseUrl}/${path}/${idPathSegment}\`)`)
    lines.push(`    if (res.status === 404) return null`)
    lines.push(`    if (!res.ok) throw new Error(\`GET /${path}/\${${isCompound ? 'Object.values(id).join("/")' : idField.name}} failed: \${res.status}\`)`)
    lines.push(`    return res.json()`)
    lines.push(`  },`)

    // create
    lines.push(`  create: async (data: ${modelName}CreateInput): Promise<${modelName}> => {`)
    lines.push(`    const res = await fetch(\`\${this.#baseUrl}/${path}\`, {`)
    lines.push(`      method: 'POST',`)
    lines.push(`      headers: { 'Content-Type': 'application/json' },`)
    lines.push(`      body: JSON.stringify(data),`)
    lines.push(`    })`)
    lines.push(`    if (!res.ok) throw new Error(\`POST /${path} failed: \${res.status}\`)`)
    lines.push(`    return res.json()`)
    lines.push(`  },`)

    // update
    lines.push(`  update: async (${idParam}, data: ${modelName}UpdateInput): Promise<${modelName}> => {`)
    lines.push(`    const res = await fetch(\`\${this.#baseUrl}/${path}/${idPathSegment}\`, {`)
    lines.push(`      method: 'PATCH',`)
    lines.push(`      headers: { 'Content-Type': 'application/json' },`)
    lines.push(`      body: JSON.stringify(data),`)
    lines.push(`    })`)
    lines.push(`    if (!res.ok) throw new Error(\`PATCH /${path}/\${${isCompound ? 'Object.values(id).join("/")' : idField.name}} failed: \${res.status}\`)`)
    lines.push(`    return res.json()`)
    lines.push(`  },`)

    // delete
    lines.push(`  delete: async (${idParam}): Promise<${modelName}> => {`)
    lines.push(`    const res = await fetch(\`\${this.#baseUrl}/${path}/${idPathSegment}\`, {`)
    lines.push(`      method: 'DELETE',`)
    lines.push(`    })`)
    lines.push(`    if (!res.ok) throw new Error(\`DELETE /${path}/\${${isCompound ? 'Object.values(id).join("/")' : idField.name}} failed: \${res.status}\`)`)
    lines.push(`    return res.json()`)
    lines.push(`  },`)
  } else {
    // No unique identifier — only create is possible beyond findMany
    lines.push(`  create: async (data: ${modelName}CreateInput): Promise<${modelName}> => {`)
    lines.push(`    const res = await fetch(\`\${this.#baseUrl}/${path}\`, {`)
    lines.push(`      method: 'POST',`)
    lines.push(`      headers: { 'Content-Type': 'application/json' },`)
    lines.push(`      body: JSON.stringify(data),`)
    lines.push(`    })`)
    lines.push(`    if (!res.ok) throw new Error(\`POST /${path} failed: \${res.status}\`)`)
    lines.push(`    return res.json()`)
    lines.push(`  },`)
  }

  lines.push(`}`)

  return lines.join('\n')
}

