import { describe, expect, test } from 'vitest'

import type * as DMMF from '@prisma/dmmf'

import { generateRestClient } from '../generate-client'

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

function makeModel(name: string, fields: DMMF.Field[], primaryKey: DMMF.PrimaryKey | null = null): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey,
  }
}

const BASE_URL = 'http://localhost:3000/api'

describe('generateRestClient', () => {
  test('generates interfaces and CRUD for a simple model', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      makeField({ name: 'email', type: 'String', isUnique: true }),
      makeField({ name: 'name', type: 'String', isRequired: false }),
    ])

    const result = generateRestClient({ models: [model], enums: [], baseUrl: BASE_URL })

    expect(result).toContain('export interface User {')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name: string | null')

    expect(result).toContain('export interface UserCreateInput {')
    // id should be excluded from CreateInput (isId + hasDefaultValue)
    expect(result).not.toMatch(/UserCreateInput \{[^}]*\bid\b/)
    expect(result).toContain('export interface UserUpdateInput {')

    expect(result).toContain('export class RestClient {')
    expect(result).toContain('readonly user = {')
    expect(result).toContain('findMany')
    expect(result).toContain('findUnique')
    expect(result).toContain('create')
    expect(result).toContain('update')
    expect(result).toContain('delete')
  })

  test('generates enum type aliases', () => {
    const enumDef: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }],
    }

    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      makeField({ name: 'role', type: 'Role', kind: 'enum' }),
    ])

    const result = generateRestClient({ models: [model], enums: [enumDef], baseUrl: BASE_URL })

    expect(result).toContain("export type Role = 'ADMIN' | 'USER'")
    expect(result).toContain('role: Role')
  })

  test('handles list fields', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      makeField({ name: 'tags', type: 'String', isList: true }),
    ])

    const result = generateRestClient({ models: [model], enums: [], baseUrl: BASE_URL })

    expect(result).toContain('tags: string[]')
  })

  test('excludes relation fields', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      makeField({ name: 'title', type: 'String' }),
      makeField({
        name: 'author',
        type: 'User',
        kind: 'object',
        relationName: 'PostToUser',
        relationFromFields: ['authorId'],
        relationToFields: ['id'],
      }),
      makeField({ name: 'authorId', type: 'Int' }),
    ])

    const result = generateRestClient({ models: [model], enums: [], baseUrl: BASE_URL })

    expect(result).toContain('title: string')
    expect(result).toContain('authorId: number')
    expect(result).not.toContain('author: User')
  })

  test('excludes @updatedAt fields from input types', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      makeField({ name: 'title', type: 'String' }),
      makeField({ name: 'updatedAt', type: 'DateTime', isUpdatedAt: true, hasDefaultValue: true }),
    ])

    const result = generateRestClient({ models: [model], enums: [], baseUrl: BASE_URL })

    // updatedAt should appear in the model interface but not in input types
    expect(result).toMatch(/export interface Post \{[^}]*updatedAt/)
    expect(result).not.toMatch(/PostCreateInput \{[^}]*updatedAt/)
    expect(result).not.toMatch(/PostUpdateInput \{[^}]*updatedAt/)
  })

  test('makes fields with defaults optional in CreateInput', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      makeField({ name: 'title', type: 'String' }),
      makeField({ name: 'published', type: 'Boolean', hasDefaultValue: true }),
    ])

    const result = generateRestClient({ models: [model], enums: [], baseUrl: BASE_URL })

    // title is required in CreateInput, published is optional
    expect(result).toMatch(/PostCreateInput \{[^}]*\n\s+title: string/)
    expect(result).toMatch(/PostCreateInput \{[^}]*\n\s+published\?: boolean/)
  })

  test('generates empty client for no models', () => {
    const result = generateRestClient({ models: [], enums: [], baseUrl: BASE_URL })

    expect(result).toContain('export class RestClient {')
    expect(result).toContain('// Generated by @prisma/generator-rest-client')
  })

  test('handles multiple models', () => {
    const user = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      makeField({ name: 'email', type: 'String' }),
    ])
    const post = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      makeField({ name: 'title', type: 'String' }),
    ])

    const result = generateRestClient({ models: [user, post], enums: [], baseUrl: BASE_URL })

    expect(result).toContain('export interface User {')
    expect(result).toContain('export interface Post {')
    expect(result).toContain('readonly user = {')
    expect(result).toContain('readonly post = {')
  })

  test('uses custom baseUrl', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
    ])

    const result = generateRestClient({ models: [model], enums: [], baseUrl: 'https://api.example.com' })

    expect(result).toContain("baseUrl: string = 'https://api.example.com'")
  })

  test('handles model with no unique identifier', () => {
    const model = makeModel('LogEntry', [
      makeField({ name: 'message', type: 'String' }),
      makeField({ name: 'level', type: 'String' }),
    ])

    const result = generateRestClient({ models: [model], enums: [], baseUrl: BASE_URL })

    expect(result).toContain('findMany')
    expect(result).toContain('create')
    // Without an ID, findUnique/update/delete should not be generated
    expect(result).not.toMatch(/logEntry[^}]*findUnique/)
    expect(result).not.toMatch(/logEntry[^}]*\bupdate\b/)
    expect(result).not.toMatch(/logEntry[^}]*\bdelete\b/)
  })
})

