    expect(content).toContain("baseUrl: string = 'http://localhost:3000/api'")
  })

  test('throws when output directory is not specified', async () => {
    const options = makeMinimalOptions(tmpDir)
    options.generator.output = null

    await expect(onGenerate(options)).rejects.toThrow('No output directory specified')
  })
})
